parameters.jsCode:
const brandName = $('Start').first().json.brand_name;

const prompts = $input.first().json.output.english_version.production_assets.image_generation_prompts;


if (!Array.isArray(prompts) || prompts.length === 0) {
  throw new Error('Agent 3 missing image_generation_prompts array');
}

const sizeMap = {
  '16:9': '1728x960',
  '3:2':  '1568x1056',
  '1:1':  '1280x1280',
  '4:3':  '1472x1088',
  '9:16': '960x1728'
};

const batchSize = prompts.length; // dynamic — matches exact number of prompts
const waitMs = 25000; // sync HTTP request handles timing naturally

return prompts.map((item, index) => ({
  json: {
    index,
    batch_size:    batchSize,
    wait_ms:       waitMs,
    brand_name:    brandName,
    asset_type:    item.asset_type,
    prompt:        item.prompt,
    aspect_ratio:  item.aspect_ratio,
    usage_context: item.usage_context,
    size:          sizeMap[item.aspect_ratio] || '1280x1280'
  }
}));

const items = $input.all();

const sizeMap = {
  '16:9': { width: 1728, height: 960  },
  '3:2':  { width: 1568, height: 1056 },
  '1:1':  { width: 1120, height: 1120 },
  '4:3':  { width: 1472, height: 1088 },
  '9:16': { width: 960,  height: 1728 }
};

return items.map(item => {
  const raw = item.json;
  const o = raw.output || raw;
  const dims = sizeMap[o.aspect_ratio] || { width: 1120, height: 1120 };

  return {
    json: {
      asset_type:       o.asset_type,
      usage_context:    o.usage_context,
      size:             o.size,
      aspect_ratio:     o.aspect_ratio,
      style_tags:       o.style_tags,
      generation_notes: o.generation_notes,
      CLOUDFLARE_ACCOUNT_ID: 'af7eb4d11cb05e46657e07f1d04e91db',
      CLOUDFLARE_API_TOKEN:  'cfut_VoVSCKVxns1C6VXozRnDPw4slKYJQ8sVQgu9DAT081c2440f',
      cf_payload: {
        prompt:    o.text || o.prompt,
        num_steps: 28,
        guidance:  6.5,
        width:     dims.width,
        height:    dims.height
      }
    }
  };
});

